SELECT * FROM customer limit 20

--Q1. What is the total revenue generated by male vs. female customers?

SELECT
gender,
SUM (purchase_amount) AS revenue
FROM customer
GROUP BY gender

--Q2. Which customers used a discount but still spent more than the average purchase amount?

SELECT
Customer_id,
purchase_amount
FROM customer
WHERE discount_applied = 'Yes' AND purchase_amount >= (SELECT AVG(purchase_amount) FROM customer)

--03. Which are the top 5 products with the highest average review rating?

SELECT
item_purchased,
ROAVG (review_rating) AS avgreview
FROM customer
GROUP BY item_purchased
ORDER BY AVG (review_rating) DESC 
limit 5;

--04. Compare the average Purchase Amounts between Standard and Express Shipping. 

SELECT
shipping_type,
ROUND (AVG(purchase_amount), 2)
FROM customer
WHERE shipping_type in ('Standard', 'Express')
GROUP BY shipping_type

--Q5. Do subscribed customers spend more? Compare average spend and total revenue between subscribers and non-subscribers.

SELECT
subscription_status,
COUNT(customer_id) AS totalcustomer,
ROUND(AVG(purchase_amount), 2)AS avgspend,
ROUND(SUM(purchase_amount),2) AS totalrevenue
FROM customer
GROUP BY subscription_status
ORDER BY totalrevenue, avgspend DESC

--Q6. Which 5 products have the highest percentage of purchases with discounts applied? 

SELECT
item_purchased,
ROUND(100 * SUM(CASE WHEN discount_applied = 'Yes' THEN 1 ELSE 0 END )/COUNT(*), 2) AS discount_rate
FROM customer
GROUP BY item_purchased
ORDER BY discount_rate DESC 
Limit 5;

--Q7. Segment customers into New, Returning, and Loyal based on their total number of previous purchases, and show the count of each segment.

WITH customer_type AS(
SELECT
Customer_id,
Previous_purchases,
CASE WHEN previous_purchases = 1 THEN 'New'
     WHEN previous_purchases BETWEEN 2 AND 10 THEN 'Returning'
	 ELSE 'Loyal'
	 END AS Customer_Segment
FROM customer
)

SELECT 
Customer_segment,
COUNT(*) AS "Number Of Customers"
FROM customer_type
GROUP BY customer_segment

--Q8. What are the top 3 most purchased products within each category? 

WITH item_counts AS (
SELECT
category,
item_purchased,
COUNT (customer_id) AS total_orders,
ROW_NUMBER () OVER (PARTITION BY category ORDER BY COUNT (customer_id) DESC) AS item_rank
FROM customer
GROUP BY category, item_purchased
)

SELECT
item_rank,
category,
item_purchased,
total_orders
FROM item_counts
WHERE item_rank <= 3

--Q9. Are customers who are repeat buyers (more than 5 previous purchases) also likely to subscribe? 

SELECT
subscription_status,
COUNT(customer_id) AS repeate_buyers
FROM customer
WHERE previous_Purchases > 5
GROUP BY subscription_status

--010. What is the revenue contribution of each age group

SELECT
age_group,
SUM(purchase_amount) AS totalrevenue
FROM customer
GROUP BY age_group
ORDER BY totalrevenue DESC




















